firmware_template.source:
#include "led_matrix.h"
#include <MD_Parola.h>
#include <MD_MAX72xx.h>
#include <SPI.h>
#define MAX_DEVICES 4
static MD_Parola mx=MD_Parola(MD_MAX72XX::FC16_HW,5,MAX_DEVICES);
void matrix_setup(){mx.begin();mx.setIntensity(5);mx.displayClear();Serial.println("[matrix] OK");}
void matrix_loop(){mx.displayAnimate();}
void matrix_scroll_text(const char*t){mx.displayScroll(t,PA_CENTER,PA_SCROLL_LEFT,75);}
void matrix_show(const char*t){mx.displayClear();mx.print(t);}
void matrix_set_brightness(uint8_t b){mx.setIntensity(b);}
